Common failure shapes and what they mean:

Rule of thumb: **if the user mentions COBS, Modbus, protobuf, CAN,
audio, or "binary", `decoderMethod: 3` is right.** If they mention
NMEA, AT-commands, CSV, line-based, or "text", `decoderMethod: 0` is
right. Hex and Base64 are niche choices for cases where the device
itself ships an encoded payload.

## Common patterns

```js
// CSV (the default)
function parse(frame) { return frame.split(','); }

// Key=value pairs (e.g. "speed=42.1,heading=180")
function parse(frame) {
  const kv = {};
  frame.split(',').forEach(p => {
    const [k, v] = p.split('=');
    kv[k] = v;
  });
  return [kv.speed || 0, kv.heading || 0];
}

// Binary little-endian (frame is a byte string)
function parse(frame) {
  const buf = new Uint8Array(frame.length);
  for (let i = 0; i < frame.length; i++) buf[i] = frame.charCodeAt(i);
  const view = new DataView(buf.buffer);
  return [view.getFloat32(0, true), view.getInt16(4, true)];
}
```

## NMEA / hex / domain protocols

For NMEA, AT-commands, hex-encoded, base64, COBS, TLV, see
`scripts.list{kind: "frame_parser_js"}`: the codebase includes ~10
reference parsers for these patterns. Adapt the closest match.

## Gotchas

Each widget has:

- `title`, `icon` — UI labels
- `minValue`, `maxValue`, `stepSize`, `initialValue` — numeric range
  (sliders, knobs)
- `transmitFunction` — JS source that returns the bytes to send

## The transmit function

The function name is `transmit`. It receives the widget's current value
(numeric for slider/knob, boolean for toggle, string for textfield, or a
sentinel for buttons) and returns either a string (sent verbatim) or a
byte array.

```js
// Simple: send a Modbus-shaped command on button click
function transmit() {
  return ":01030000000AF1\r\n";
}

// Slider: send a 16-bit big-endian value
function transmit(value) {
  const v = Math.round(value) & 0xFFFF;
  return new Uint8Array([0xA5, (v >> 8) & 0xFF, v & 0xFF]);
}

// Toggle: send different payload per state
function transmit(checked) {
  return checked ? "RELAY ON\n" : "RELAY OFF\n";
}

// TextField: prepend AT prefix
function transmit(text) {
  return "AT+" + text + "\r\n";
}
```

## Iteration workflow

1. Get current config: `project.outputWidget.get{groupId, widgetId}` —
   preserve user-set ranges/labels when rewriting `transmitFunction`.
2. Read scripting reference:
   `meta.fetchScriptingDocs{kind: "output_widget_js"}`.
3. Adapt a real example: `scripts.list{kind: "output_widget_js"}` ships
   helpers for CRC16/CRC32, NMEA checksums, Modbus framing, SLCAN, GRBL,
   GCode, SCPI, binary packet builders.
4. Push: `project.outputWidget.update{groupId, widgetId,
   transmitFunction: "..."}`.

### Recipe: spectrum analyzer painter

```js
// Top-level: bootstrap once at compile time
var SAMPLES = 1024;
var ring    = new Array(SAMPLES).fill(0);
var spectrum = new Array(SAMPLES / 2).fill(0);
var head    = 0;

function onFrame() {
  // Cheap: copy the latest sample into the ring
  var v = datasetGetFinal(/*uniqueId*/ 0);
  if (typeof v !== 'number') return;
  ring[head] = v;
  head = (head + 1) % SAMPLES;

// Run FFT on tick (24 Hz), not on every parsed frame -- a 48 kHz
  // audio source emits 48000 frames/s; we only render 24/s, so doing
  // FFT here gets us a ~2 kHz redraw rate against a recent window.
  spectrum = computeFFT(ring, head);
}

function paint(ctx, w, h) {
  ctx.fillStyle = theme.widget_base;
  ctx.fillRect(0, 0, w, h);
  ctx.strokeStyle = theme.widget_highlight;
  ctx.beginPath();
  ctx.moveTo(0, h);
  for (var i = 0; i < spectrum.length; ++i) {
    var x = (i / spectrum.length) * w;
    var y = h - spectrum[i] * h;
    ctx.lineTo(x, y);
  }
  ctx.stroke();
}
```

Without `onFrame`, that FFT would run inside `paint` and recompute on
every redraw, including ones triggered by mouse hover and theme
changes. With it, `paint` only laces lines through the cached
`spectrum` array.

## Iteration workflow

For a SPECIFIC dataset, prefer the resolvers over walking the tree:
```
project.dataset.getByPath { path: "Group/Dataset" }
project.dataset.getByPath { path: "Source/Group/Dataset" }
project.dataset.getByTitle { title: "...", groupId?, sourceId? }
project.dataset.getByUniqueId { uniqueId: ... }
```

`group.list` is denser than `dataset.list`: it shows groups and a
summary of each dataset (title, units, uniqueId, etc.). Use it when
you need group-level metadata; use `project.snapshot` when you need
the whole picture in one shot.

## Identifiers: what's stable, what's not

40 sequential `project.dataset.update` calls is 40 round-trips AND 40
autosave-debounce restarts. The batch endpoints collapse that into ONE
suspended-autosave window with one final save.

### `project.batch`: exact shape

The parameter is `ops` (NOT `commands`, NOT `mutations`, NOT `requests`).
Each op is `{command: string, params: object}`. Both fields are
required. If you only have `{command, ...}` with params spread at the
top level, the op is rejected.

```json
{
  "ops": [
    {
      "command": "project.dataset.update",
      "params": { "groupId": 0, "datasetId": 0, "title": "LED 1", "index": 1 }
    },
    {
      "command": "project.dataset.update",
      "params": { "groupId": 0, "datasetId": 1, "title": "LED 2", "index": 2 }
    }
  ],
  "stopOnError": false
}
```

## Per-dataset isolation

Your transform script is wrapped in an IIFE at compile time:

```js
(function() {
  /* your code */
  return typeof transform === 'function' ? transform : null;
})()
```

Top-level `var/let/const` are private per dataset, even when several
datasets in the same source share a JS engine. Two datasets can both
declare `let alpha = 0.2` without clobbering each other.

## Iteration workflow

## Examples (JavaScript, when Lua won't do)

```js
let ema = 0;
const alpha = 0.2;
function transform(value) {
  ema = alpha * value + (1 - alpha) * ema;
  return ema;
}
```

For ~20 more reference transforms (clamp, dead-zone, ADC-to-voltage,
celsius/fahrenheit, accumulator, autozero, bit extract, ...), call
`scripts.list{kind: "transform_lua"}` or
`scripts.list{kind: "transform_js"}`.

## Frame metadata: second `info` argument

Transforms receive `{frameNumber, sourceId, timestampMs}` as a second arg.
One-arg transforms keep working unchanged (both languages ignore extras).
`timestampMs` is a **monotonic** ms counter (steady clock), not wall
clock. Use it for deltas only.

Avoid:

- Building intermediate objects per call
- Catching exceptions in the hot path — let parse errors bubble; the runtime
  watchdog handles them
- `JSON.parse` on every frame unless the protocol is JSON-line

## Examples

### CSV split (most common)

```js
function parse(frame, separator) {
  return frame.split(separator);
}
```

### Tab-delimited with numeric coercion

```js
function parse(frame /*, separator */) {
  const parts = frame.split('\t');
  const out = new Array(parts.length);
  for (let i = 0; i < parts.length; ++i)
    out[i] = parseFloat(parts[i]);
  return out;
}
```

### Regex extraction

```js
const RE = /^\$([A-Z]+),(-?\d+\.\d+),(-?\d+\.\d+),(-?\d+)\*([0-9A-F]{2})/;

function parse(frame /*, separator */) {
  const m = frame.match(RE);
  if (!m)
    return [];
  return [parseFloat(m[2]), parseFloat(m[3]), parseInt(m[4], 10)];
}
```

### JSON-line

```js
function parse(frame /*, separator */) {
  try {
    const obj = JSON.parse(frame);
    return [obj.x, obj.y, obj.z];
  } catch (_e) {
    return [];
  }
}
```

### Batched samples (one frame yields N rows)

If your device emits multiple sensor rows per frame, return a 2-D array;
the FrameBuilder will flatten to multiple frames.

```js
function parse(frame) {
  const values = frame.split(",");
  if (parseFloat(values[0]) > 80) {
    const r = deviceWrite("ALARM=1\n");
    if (!r.ok) console.warn("alarm write failed:", r.error);
  }
  return values;
}
```

## Firing project actions — `actionFire()`

```js
actionFire(actionId) -> { ok: true } | { ok: false, error: "..." }
```

Reuses an existing project Action (with its prebuilt payload + timer
mode). `actionId` is the action's stable id, NOT its index in the list.
Same shape as `deviceWrite`; never throws.

## Dashboard controls

Seven UI helpers, all returning `{ ok: true }` or `{ ok: false, error: "..." }`. None of them log. Call once on a state transition, NOT on every frame.

```js
clearPlots()                          // wipe line/multiplot/FFT/GPS/3D/waterfall buffers
setPlotPoints(n)                      // horizontal sample window (n >= 1)
setTerminalVisible(visible)           // bool
setNotificationLogVisible(visible)    // bool
setClockVisible(visible)              // bool
setStopwatchVisible(visible)          // bool
setActiveWorkspace(idOrName)          // workspaceId (int >= 1000) OR title (case-insensitive)
```

Typical use: reset a GPS trace the moment a valid fix arrives so the line from origin to first real sample disappears.

```js
var hadFix = false;
function parse(frame) {
  const [lat, lon, q] = frame.split(",").map(parseFloat);
  if (!hadFix && q > 0) {
    clearPlots();
    hadFix = true;
  }
  return [lat, lon, q];
}
```

## Examples

### Toggle a relay (single byte)

```js
function output(state) {
  return new Uint8Array([state.on ? 0x01 : 0x00]);
}
```

### NMEA $PXSEND on submit

```js
function output(state) {
  if (!state.submitted)
    return null;
  return nmea('PXSEND,' + state.text);
}
```

### PWM duty (slider) over Modbus

```js
function output(state) {
  const duty = Math.round(state.value);
  return modbusWriteSingle(0x01, 0x0010, duty);
}
```

### Binary command frame with CRC-16

```js
function output(state) {
  if (!state.pressed)
    return null;

const body = new Uint8Array([0xAA, 0x55, 0x01]);
  const checksum = crc16(body);
  const out = new Uint8Array(body.length + 2);
  out.set(body, 0);
  out[body.length]     = checksum & 0xFF;
  out[body.length + 1] = (checksum >> 8) & 0xFF;
  return out;
}
```

// theme -- ThemeManager palette, always in sync with the active theme.
// PRIMARY keys for painters (these match what the QML dashboard widgets
// already use, so a painter-rendered widget visually fits the rest of the
// dashboard):
theme.widget_base       // canvas / card background
theme.widget_border     // grid lines, frames, outlines
theme.widget_text       // primary value labels and titles
theme.widget_highlight  // primary signal / value colour
theme.alarm             // red, used for alarm states / second hand / errors
theme.placeholder_text  // muted secondary labels
theme.pane_section_label // small caption text
theme.widget_colors     // ARRAY of per-channel distinct colors, indexable
                        // as theme.widget_colors[i % theme.widget_colors.length]
// Other keys also exist (text, window, base, mid, highlight, accent,
// link, error, groupbox_background, ...) but prefer the widget_* ones
// above for painter content -- they're tuned for in-widget rendering.

// console -- log/warn/error to the editor status pane
console.log("...")
console.warn("...")
console.error("...")

// Data-table API (shared with transforms; see "Tables and registers")
tableGet(tableName, registerName)              // -> number | string
tableSet(tableName, registerName, value)       // user-table writes only
datasetGetRaw(uniqueId)                        // raw value of any dataset
datasetGetFinal(uniqueId)                      // final value of any dataset

// Closed-loop control APIs (shared with parsers and transforms)
deviceWrite(data, sourceId?)                   // -> { ok, error? }
actionFire(actionId)                           // -> { ok, error? }

Bands may have gaps and may overlap. Severity ≥ Warning posts a
notification when the value enters the band (3-second per-widget
cooldown suppresses oscillation spam).

```js
// Find the band a value sits in (linear scan; band counts are tiny)
function bandFor(ds, value) {
  if (!ds.alarmBands) return null;
  for (var i = 0; i < ds.alarmBands.length; i++) {
    var b = ds.alarmBands[i];
    if (value >= b.min && value <= b.max) return b;
  }
  return null;
}

function colorFor(ds, value) {
  var b = bandFor(ds, value);
  if (!b) return theme.widget_highlight;
  if (b.color && b.color.length) return b.color;
  // Severity defaults match the QML widgets' theme palette
  if (b.severity >= 3) return theme.alarm;
  return theme.widget_highlight;
}
```

function paint(ctx, w, h) {
  var speed = datasetGetFinal(SPEED_UID) || 0;
  var rpm   = datasetGetFinal(RPM_UID)   || 0;
  // ...draw using speed and rpm without owning any datasets in this group
}
```

Why not duplicate datasets into the painter group? Because every dataset
in a project costs a frame-table register, an exporter column, a
dashboard row, and a project-file entry. Painters that just READ values
should not own them.

## Tables and registers (the central data bus)

Data tables let multiple scripts (transforms, painters) share state.
Two register types:

The `theme` global stays in sync when the user switches between light
and dark themes. Hard-coded hex breaks that.

## Worked example 1: progress rings (multi-dataset)

Lays out one circular ring per dataset. Demonstrates a square-ish grid,
arc + moveTo discipline, and a value/title centre.

```js
function paint(ctx, w, h) {
  ctx.fillStyle = theme.widget_base;
  ctx.fillRect(0, 0, w, h);
  ctx.strokeStyle = theme.widget_border;
  ctx.lineWidth = 2;
  ctx.strokeRect(1, 1, w - 2, h - 2);

if (datasets.length === 0) return;

var n    = datasets.length;
  var cols = Math.min(n, Math.max(1, Math.round(Math.sqrt(n * w / h))));
  var rows = Math.ceil(n / cols);
  var pad  = 12;
  var cw   = (w - pad * 2) / cols;
  var ch   = (h - pad * 2) / rows;

for (var i = 0; i < n; i++) {
    var col = i % cols;
    var row = Math.floor(i / cols);
    var cx  = pad + cw * col + cw * 0.5;
    var cy  = pad + ch * row + ch * 0.5 - 6;
    var rr  = Math.max(10, Math.min(cw, ch) * 0.38 - 4);
    var ds  = datasets[i];
    var v   = Number.isFinite(ds.value) ? ds.value : 0;
    var span = (ds.max - ds.min) || 1;
    var norm = Math.max(0, Math.min(1, (v - ds.min) / span));

// Track ring (full circle, the same color the dashboard uses for grid lines).
    ctx.strokeStyle = theme.widget_border;
    ctx.lineWidth   = 12;
    ctx.lineCap     = "butt";
    ctx.beginPath();
    ctx.moveTo(cx + rr, cy);
    ctx.arc(cx, cy, rr, 0, Math.PI * 2);
    ctx.stroke();

// Value arc -- pick a per-channel color from theme.widget_colors so
    // multi-channel painters use the same palette as multiplots.
    if (norm > 0) {
      var startA = -Math.PI * 0.5;
      var endA   = startA + Math.PI * 2 * norm;
      var palette = theme.widget_colors || [theme.widget_highlight];
      ctx.strokeStyle = palette[i % palette.length];
      ctx.lineCap     = "round";
      ctx.beginPath();
      ctx.moveTo(cx + Math.cos(startA) * rr, cy + Math.sin(startA) * rr);
      ctx.arc(cx, cy, rr, startA, endA);
      ctx.stroke();
      ctx.lineCap = "butt";
    }

// Centre value.
    ctx.fillStyle    = theme.widget_text;
    ctx.font         = "bold 18px sans-serif";
    ctx.textAlign    = "center";
    ctx.textBaseline = "middle";
    ctx.fillText((norm * 100).toFixed(0) + "%", cx, cy);

// Title under the ring.
    ctx.fillStyle    = theme.placeholder_text || theme.widget_text;
    ctx.font         = "10px sans-serif";
    ctx.textBaseline = "alphabetic";
    ctx.fillText((ds.title || "").substring(0, 16), cx, cy + rr + 18);
  }

ctx.textAlign    = "start";
  ctx.textBaseline = "alphabetic";
}
```

## Worked example 2: status grid (peer-dataset reads, no own datasets)

Demonstrates a painter group with `datasets.length === 0`. The script
reads **peer** datasets by uniqueId (discovered ahead of time via
`project.dataset.list`) and renders a coloured status tile per channel.

```js
// Peer dataset uniqueIds, discovered via project.dataset.list. Each
// constant is set once at script load; edit the script if your project
// layout changes.
var CHANNELS = [
  { uid: 10001, label: "Voltage",   warn: 11.0, alarm: 10.5 },
  { uid: 10002, label: "Current",   warn: 8.0,  alarm: 9.5  },
  { uid: 10003, label: "Temp",      warn: 70,   alarm: 85   },
  { uid: 10004, label: "Pressure",  warn: 110,  alarm: 130  }
];

function tileColor(value, c) {
  if (!Number.isFinite(value)) return theme.widget_border;
  if (value >= c.alarm) return theme.alarm;
  if (value >= c.warn)  return theme.accent;
  return theme.widget_highlight;
}

function paint(ctx, w, h) {
  ctx.fillStyle = theme.widget_base;
  ctx.fillRect(0, 0, w, h);

var pad  = 8;
  var cols = 2;
  var rows = Math.ceil(CHANNELS.length / cols);
  var cw   = (w - pad * (cols + 1)) / cols;
  var ch   = (h - pad * (rows + 1)) / rows;

for (var i = 0; i < CHANNELS.length; i++) {
    var c    = CHANNELS[i];
    var x    = pad + (i % cols) * (cw + pad);
    var y    = pad + Math.floor(i / cols) * (ch + pad);
    var v    = datasetGetFinal(c.uid);

ctx.fillStyle = tileColor(v, c);
    ctx.fillRect(x, y, cw, ch);

ctx.fillStyle    = theme.highlighted_text || theme.widget_text;
    ctx.font         = "bold 14px sans-serif";
    ctx.textAlign    = "left";
    ctx.textBaseline = "top";
    ctx.fillText(c.label, x + 8, y + 8);

ctx.font         = "bold 22px sans-serif";
