/**
 * @brief Parses a JSON-encoded frame from Serial Studio and extracts ISS telemetry data.
 *
 * This function takes a string `frame` that is expected to be a valid JSON object
 * containing at least the keys: `latitude`, `longitude`, `altitude`, and `velocity`.
 * If the frame is non-empty and successfully parsed, it returns these values as an array.
 * If the frame is empty, it returns an empty array.
 *
 * @param frame A JSON string containing telemetry data.
 * @return An array in the order [latitude, longitude, altitude, velocity], 
 *         or an empty array if the input is invalid or empty.
 */
function parse(frame) {
    if (frame.length > 0) {
        let data = JSON.parse(frame);
        return [data.latitude, data.longitude, data.altitude, data.velocity];
    }

    return [];
}

